fbMonitoringChannel(
	HB_Manual_OK := EVL.HB_Manual_OK, 
	HB_Remote_OK := EVL.HB_Remote_OK,
	HB_Auto_OK	 := EVL.HB_Auto_OK, 
	HB_Remote_Mobile_OK := EVL.HB_Remote_Mobile_OK
);

fbShutdownService( 
	EmergencyShutdown := fbMonitoringChannel.EmergencyShutdown
);

HB_Manual_Fail := NOT HB_Manual_OK; 
HB_Remote_Fail := NOT HB_Remote_OK; 
HB_Auto_Fail   := NOT HB_Auto_OK;
HB_Remote_Mobile_Fail := NOT HB_Remote_Mobile_OK; 

IF HB_Manual_Fail AND HB_Remote_Fail AND HB_Auto_Fail AND HB_Remote_Mobile_Fail THEN 
	EmergencyShutdown := TRUE; 
END_IF

//Once triggered, the alert stays TRUE until system restart

IF EmergencyShutdown THEN 
	Alert := TRUE; 
END_IF

CR710S_Config(); //IO Configuration
IOWrapper.READ_INPUTS(); //Call IOWrapper Main Program and Read Data from Inputs
fbInputProcessing( xReqManual := IN0100.VAR_OUT.xValueDigital, xAckManual := IN0101.VAR_OUT.xValueDigital, xRelManual := IN0102.VAR_OUT.xValueDigital, xHB_Manual := IN0103.VAR_OUT.xValueDigital, xReqRemote := GVL_IO.ReqRemote, xAckRemote := GVL_IO.AckRemote, xRelRemote := GVL_IO.RelRemote, xHB_Remote := GVL_HeartBeat.HB_Remote_Signal, xReqAuto := GVL_IO.ReqAuto, xAckAuto := GVL_IO.AckAuto, xRelAuto := GVL_IO.RelAuto, xHB_Auto := GVL_HeartBeat.HB_Auto_Signal, xReqRemoteMobile := GVL_IO.ReqRemoteMobile, xAckRemoteMobile := GVL_IO.AckRemoteMobile, xRelRemoteMobile := GVL_IO.RelRemoteMobile, xHB_Remote_Mobile := GVL_HeartBeat.HB_Remote_Mobile_Signal
);
fbHB_Manual(xSignal := GVL_HeartBeat.HB_Manual_Signal); fbHB_Remote(xSignal := GVL_HeartBeat.HB_Remote_Signal); fbHB_Auto(xSignal := GVL_HeartBeat.HB_Auto_Signal); fbHB_Remote_Mobile(xSignal := GVL_HeartBeat.HB_Remote_Mobile_Signal);
//Heartbeat generator fbHBGen_Manual(); fbHBGen_Remote(); fbHBGen_Auto(); fbHBGen_Remote_Mobile();
fbIntegrityCheck( ReqManual := fbInputProcessing.ReqManual, ReqRemote := fbInputProcessing.ReqRemote, ReqAuto := fbInputProcessing.ReqAuto, ReqRemoteMobile := fbInputProcessing.ReqRemoteMobile, AckManual := fbInputProcessing.AckManual, AckRemote := fbInputProcessing.AckRemote, AckAuto := fbInputProcessing.AckAuto, AckRemoteMobile := fbInputProcessing.AckRemoteMobile, RelManual := fbInputProcessing.RelManual, RelRemote := fbInputProcessing.RelRemote, RelAuto := fbInputProcessing.RelAuto, RelRemoteMobile := fbInputProcessing.RelRemoteMobile, HB_Manual_Signal := fbInputProcessing.HB_Manual_Signal, HB_Remote_Signal := fbInputProcessing.HB_Remote_Signal, HB_Auto_Signal := fbInputProcessing.HB_Auto_Signal, HB_Remote_Mobile_Signal := fbInputProcessing.HB_Remote_Mobile_Signal, );
fbControlUnit( ReqManual := fbInputProcessing.ReqManual, AckManual := fbInputProcessing.AckManual, RelManual := fbInputProcessing.RelManual, ReqRemote := fbInputProcessing.ReqRemote, AckRemote := fbInputProcessing.AckRemote, RelRemote := fbInputProcessing.RelRemote, ReqAuto := fbInputProcessing.ReqAuto, AckAuto := fbInputProcessing.AckAuto, RelAuto := fbInputProcessing.RelAuto, ReqRemoteMobile := fbInputProcessing.ReqRemoteMobile, AckRemoteMobile := fbInputProcessing.AckRemoteMobile, RelRemoteMobile := fbInputProcessing.RelRemoteMobile, HB_Manual_OK := GVL_HeartBeat.HB_Manual_OK, HB_Remote_OK := GVL_HeartBeat.HB_Remote_OK, HB_Auto_OK := GVL_HeartBeat.HB_Auto_OK, HB_Remote_Mobile_OK := GVL_HeartBeat.HB_Remote_Mobile_OK, Valid := fbIntegrityCheck.Valid );
fbOutputProcessing( ReqManual := GVL_IO.ReqManual, ReqRemote := GVL_IO.ReqRemote, ReqAuto := GVL_IO.ReqAuto, ReqRemoteMobile := GVL_IO.ReqRemoteMobile, GrantedManual := fbControlUnit.GrantedManual, GrantedRemote := fbControlUnit.GrantedRemote, GrantedAuto := fbControlUnit.GrantedAuto, GrantedRemoteMobile := fbControlUnit.GrantedRemoteMobile, Released := fbControlUnit.Released, PendingReady := fbControlUnit.PendingReady, Active := fbControlUnit.Active, State := fbControlUnit.State, HB_Manual_OK := GVL_HeartBeat.HB_Manual_OK, HB_Remote_OK := GVL_HeartBeat.HB_Remote_OK, HB_Auto_OK := GVL_HeartBeat.HB_Auto_OK, HB_Remote_Mobile_OK := GVL_HeartBeat.HB_Remote_Mobile_OK );
fbDecisionLogger( Active := fbControlUnit.Active, Pending := fbControlUnit.Pending, State := fbControlUnit.State, RejectedRequestFlag := fbControlUnit.RejectedRequestFlag, RejectionReason := fbControlUnit.RejectionReason
);
OUT0000.VAR_IN.uiValue := SEL(fbOutputProcessing.Out_GrantedManual, 0, 2500); OUT0001.VAR_IN.uiValue := SEL(fbOutputProcessing.Out_GrantedRemote, 0, 2500); OUT0002.VAR_IN.uiValue := SEL(fbOutputProcessing.Out_ActiveManual, 0, 2500); OUT0003.VAR_IN.uiValue := SEL(fbOutputProcessing.Out_ActiveRemote, 0, 2500); OUT0004.VAR_IN.uiValue := SEL(fbOutputProcessing.Out_Pending, 0, 2500); OUT0005.VAR_IN.uiValue := SEL(fbOutputProcessing.Out_FailSafe, 0, 2500);
OUT0006.VAR_IN.uiValue := SEL(fbOutputProcessing.Out_GrantedAuto, 0, 2500); OUT0007.VAR_IN.uiValue := SEL(fbOutputProcessing.Out_ActiveAuto, 0, 2500);
