OUT0105.CONFIG.SET_DIAG_LVL_PROT	(0, 2500, 100, eDIAG_PROT_MODE.DIAG_PROT);
OUT0106.CONFIG.SET_DIAG_LVL_PROT	(0, 4000, 100, eDIAG_PROT_MODE.DIAG_PROT);
OUT0107.CONFIG.SET_DIAG_LVL_PROT	(0, 4000, 100, eDIAG_PROT_MODE.DIAG_PROT);

xPulse := (xSignal <> xPrevSignal);
xPrevSignal := xSignal;
// Om ingen ny puls kommer, låt timern gå 
tonTimeout(IN := NOT xPulse, PT := GVL_HeartBeat.HB_Monitor_Timeout);
xOk := NOT tonTimeout.Q;

//Detect when a request signal goes from FALSE to TRUE
//Ensures each request is only processed once per button press
xReqRemotePulse := ReqRemote AND NOT xReqRemoteOld; 
xReqManualPulse := ReqManual AND NOT xReqManualOld; 
xReqAutoPulse := ReqAuto AND NOT xReqAutoOld; 
xReqRemoteMobilePulse := ReqRemoteMobile AND NOT xreqRemoteMobileOld; 

//Store previous signal state for next scan's edge detection
xReqRemoteOld := ReqRemote; 
xReqManualOld := ReqManual; 
xReqAutoOld := ReqAuto; 
xReqRemoteMobileOld := ReqRemoteMobile; 

//Safety guard - if active loses heartbeat force FAILSAFE immediately
//This check runs every scan before the state machine, acting as an interrupt
IF (Active = EControlMode.REMOTE AND NOT HB_Remote_OK) OR 
	(Active = EControlMode.MANUAL AND NOT HB_Manual_OK) OR 
	(Active = EControlMode.AUTO AND NOT HB_Auto_OK) OR 
	(Active = EControlMode.REMOTE_MOBILE AND NOT HB_Remote_Mobile_OK) THEN
	Active 	:= EControlMode.FAILSAFE; 
	Pending := EPendingMode.NONE; 
	State 	:= ETransitionState.FAILSAFE; 
	GrantedManual 		:= FALSE;
	GrantedRemote 		:= FALSE;
	GrantedAuto 		:= FALSE;
	GrantedRemoteMobile := FALSE; 
	RETURN; 
END_IF 

//Safety guard - if IntegrityCheck detected invalid signal combination force FAILSAFE
//Prevents corrupted or contradictiory signals from reaching decision logic
IF NOT Valid THEN
	Active 			:=  EControlMode.FAILSAFE;
	Pending 		:= EPendingMode.NONE;
	State 			:= ETransitionState.FAILSAFE;
	PendingReady 	:= FALSE;
	Released 		:= FALSE;
	tAckTimer(IN := FALSE, PT := MaxAckTime);
	GrantedManual := FALSE;
	GrantedRemote := FALSE;
	GrantedAuto := FALSE;
	GrantedRemoteMobile := FALSE; 
	RejectedRequestFlag := TRUE;
	RejectionReason := 'FAILSAFE: INVALID_SIGNAL';
	RETURN;	
END_IF

//Main state machine - contrls transitions between control stations
//States: INIT -> STABLE <-> PRE_TAKEOVER <-> VALIDATE_TAKEOVER, any state -> FAILSAFE
CASE State OF
	//INIT - system startup, waiting for the first valid request
	//System remains here until a station with valid heartbeat requests control 
	ETransitionState.INIT:
		IF xReqManualPulse AND HB_Manual_OK THEN
            Active := EControlMode.MANUAL;
            State  := ETransitionState.STABLE;
        ELSIF xReqRemotePulse AND HB_Remote_OK THEN
            Active := EControlMode.REMOTE;
            State  := ETransitionState.STABLE;
        ELSIF xReqAutoPulse AND HB_Auto_OK THEN
            Active := EControlMode.AUTO;
            State  := ETransitionState.STABLE;
		ELSIF xReqRemoteMobilePulse AND HB_Remote_Mobile_OK THEN 
			Active := EControlMode.REMOTE_MOBILE; 
			State := ETransitionState.STABLE; 
        END_IF 

	// FAILSAFE - terminal error state, no transitions allowed
	// Entered when heartbeat is lost, signals are invalid or internal inconsistency detected
	//Requires manual intervention to recover	
	ETransitionState.FAILSAFE:
		Pending       	:= EPendingMode.NONE;
		PendingReady	:= FALSE;
		Released 		:= FALSE;
		tAckTimer(IN := FALSE, PT := MaxAckTime);

	//STABLE - normal operating state, one station is active, no transition in progress
	// Resets rejection flags and waits for a new takeover request	
	ETransitionState.STABLE: 
		Pending := EPendingMode.NONE; 
		tAckTimer(IN := FALSE, PT := MaxAckTime);
		RejectedRequestFlag := FALSE; 
		RejectionReason := ''; 

		//Priority order dor simultaneius requests: MANUAL > REMOTE > AUTO > REMOTE_MOBILE
		//Documented in ADR-X - simultaneous requests from different stations
		IF xReqManualPulse THEN 
			xPendingManualLatch := TRUE; 
			State := ETransitionState.PRE_TAKEOVER; 
		ELSIF xReqRemotePulse THEN 
			xPendingRemoteLatch := TRUE; 
			State := ETransitionState.PRE_TAKEOVER; 
		ELSIF xReqAutoPulse THEN 
			xPendingAutoLatch := TRUE; 
			State := ETransitionState.PRE_TAKEOVER; 
		ELSIF xReqRemoteMobilePulse THEN 
			xPendingRemoteMobileLatch := TRUE; 
			State := ETransitionState.PRE_TAKEOVER; 
		END_IF

	//PRE_TAKEOVER - validates wheter a takover request can proceed
	//Checks that requesting station is not already active and has valid heartbeat
	//Rejected request are logged with reason
	ETransitionState.PRE_TAKEOVER:	
		IF xPendingManualLatch AND Active <> EControlMode.MANUAL AND HB_Manual_OK THEN 
			Pending := EPendingMode.PENDING_MANUAL; 
			State 	:= ETransitionState.VALIDATE_TAKEOVER; 
		ELSIF xPendingRemoteLatch AND Active <> EControlMode.REMOTE AND HB_Remote_OK THEN 
			Pending := EPendingMode.PENDING_REMOTE; 
			State 	:= ETransitionState.VALIDATE_TAKEOVER; 
		ELSIF xPendingAutoLatch AND Active <> EControlMode.AUTO AND HB_Auto_OK THEN 
			Pending := EPendingMode.PENDING_AUTO; 
			State 	:= ETransitionState.VALIDATE_TAKEOVER; 
		ELSIF xPendingRemoteMobileLatch AND Active <> EControlMode.REMOTE_MOBILE AND HB_Remote_Mobile_OK THEN 
			Pending := EPendingMode.PENDING_REMOTE_MOBILE; 
			State	:= ETransitionState.VALIDATE_TAKEOVER; 
		ELSE 
			//Request rejected - log reason for decision logger
			Pending := EPendingMode.NONE; 
			State := ETransitionState.STABLE; 
			RejectedRequestFlag := TRUE; 
			IF (xPendingManualLatch AND NOT HB_Manual_OK) OR 
				(xPendingRemoteLatch AND NOT HB_Remote_OK) OR 
				(xPendingAutoLatch AND NOT HB_Auto_OK) OR 
				(xPendingRemoteMobileLatch AND NOT HB_Remote_Mobile_OK) THEN 
					RejectionReason := 'Request rejected: Heartbeat failure'; 
			ELSIF (xPendingManualLatch AND Active = EControlMode.MANUAL) OR 
				(xPendingRemoteLatch AND Active = EControlMode.REMOTE) OR
				(xPendingAutoLatch AND Active = EControlMode.AUTO) OR 
				(xPendingRemoteMobileLatch AND Active = EControlMode.REMOTE_MOBILE) THEN  
					RejectionReason := 'Request rejection: Station already active'; 
			ELSE 
					RejectionReason := 'Request rejected: Conflicting request'; 
			END_IF
		END_IF

		//Clear all latches regardless of outcome - each request is only evaluated once
		xPendingManualLatch := FALSE; 
		xPendingRemoteLatch := FALSE; 
		xPendingAutoLatch 	:= FALSE;
		xPendingRemoteMobileLatch := FALSE; 


		//IF Velocity > MaxVelocity OR SteeringAngle > MaxSteering THEN 
			//not allowed
		//ELSIF xReqManualPulse AND NOT xReqRemotePulse AND Active <> EControlMode.MANUAL AND HB_Manual_OK THEN 
			//Pending := EPendingMode.PENDING_MANUAL; 
			//State := ETransitionState.PENDING_ACK; 
		//ELSIF xReqRemotePulse AND NOT xReqManualPulse AND Active <> EControlMode.REMOTE AND HB_Remote_OK THEN 
			//Pending := EPendingMode.PENDING_REMOTE; 
			//State := ETransitionState.PENDING_ACK; 
		//END_IF

	//VALIDATE_TAKEOVER - handshake phase, waiting for release from active and ack from pending
	//Transition completes when active station releases and pending station acknowledges
	//Aborted if heartbeat is lost or acknowledgement timer expires
	ETransitionState.VALIDATE_TAKEOVER: 
		tAckTimer(IN := TRUE, PT := MaxAckTime); 

		//Stop transition if the new station loses connection or cancels its request
		IF (Pending = EPendingMode.PENDING_MANUAL AND (NOT ReqManual OR NOT HB_Manual_OK)) OR
			(Pending = EPendingMode.PENDING_REMOTE AND (NOT ReqRemote OR NOT HB_Remote_OK)) OR 
			(Pending = EPendingMode.PENDING_AUTO AND (NOT ReqAuto OR NOT HB_Auto_OK)) OR 
			(Pending = EPendingMode.PENDING_REMOTE_MOBILE AND (NOT ReqRemoteMobile OR NOT HB_Remote_Mobile_OK)) THEN  
			Pending := EPendingMode.NONE; 
			State := ETransitionState.STABLE; 
			tAckTimer (IN := FALSE, PT := MaxAckTime); // Reset timer
			PendingReady := FALSE;
			Released := FALSE;
			RejectedRequestFlag := TRUE; 
			RejectionReason := 'Request rejected: Heartbeat loss during handover'; 

		//Abort - pending station did not acknowledge within allowed time
		ELSIF tAckTimer.Q THEN 
			Pending := EPendingMode.NONE; 
			State := ETransitionState.STABLE; 
			tAckTimer(IN := FALSE, PT := MaxAckTime); 
			PendingReady := FALSE;
			Released := FALSE;
			RejectedRequestFlag := TRUE; 
			RejectionReason := 'Request rejected: acknowledgement timeout'; 

		ELSE
			//Read release signal from active station
			Released := FALSE;
			CASE Active OF 
				EControlMode.MANUAL: Released := RelManual; 
				EControlMode.REMOTE: Released := RelRemote; 
				EControlMode.AUTO: Released := RelAuto; 
				EControlMode.REMOTE_MOBILE: Released := RelRemoteMobile; 
			END_CASE	

			//Read acknowledgement from pending station
			PendingReady := FALSE;
			CASE Pending OF 
				EPendingMode.PENDING_MANUAL: PendingReady := AckManual; 
				EPendingMode.PENDING_REMOTE: PendingReady := AckRemote; 
				EPendingMode.PENDING_AUTO: PendingReady := AckAuto; 
				EPendingMode.PENDING_REMOTE_MOBILE: PendingReady := AckRemoteMobile; 
			END_CASE

			//Safety check: the new station must not be the same as the current one
			//PRE_TAKEOVER prevents this, but if reached here it indicates internal fault
			IF (Pending = EPendingMode.PENDING_MANUAL AND Active = EControlMode.MANUAL) OR
				(Pending = EPendingMode.PENDING_REMOTE AND Active = EControlMode.REMOTE) OR
				(Pending = EPendingMode.PENDING_AUTO AND Active = EControlMode.AUTO) OR
				(Pending = EPendingMode.PENDING_REMOTE_MOBILE AND Active = EControlMode.REMOTE_MOBILE) THEN
					Active 			:= EControlMode.FAILSAFE;
					Pending 		:= EPendingMode.NONE;
					State			:= ETransitionState.FAILSAFE;
					PendingReady 	:= FALSE;
					Released		:= FALSE;
					tAckTimer(IN := FALSE, PT := MaxAckTime);
					GrantedManual 	:= FALSE;
					GrantedRemote 	:= FALSE;
					GrantedAuto 	:= FALSE;
					GrantedRemoteMobile := FALSE; 
					RejectedRequestFlag := TRUE; 
					RejectionReason := 'Request rejected: Integrity violation, pending matches active';
					RETURN;		
			END_IF

			//Complete transition - both conditions met
			IF Released AND PendingReady THEN 
				CASE Pending OF
					EPendingMode.PENDING_MANUAL: Active := EControlMode.MANUAL; 
					EPendingMode.PENDING_REMOTE: Active := EControlMode.REMOTE; 
					EPendingMode.PENDING_AUTO: Active := EControlMode.AUTO; 
					EPendingMode.PENDING_REMOTE_MOBILE: Active := EControlMode.REMOTE_MOBILE; 
				END_CASE
				Pending := EPendingMode.NONE; 
				State := ETransitionState.STABLE; 
				tAckTimer(IN := FALSE, PT := MaxAckTime); 
				PendingReady := FALSE;
				Released := FALSE; 
			END_IF
	END_IF
END_CASE

//Grant signals - updated each scan based on current pending mode
//Stations use these to know their request has been approved
GrantedManual := (Pending = EPendingMode.PENDING_MANUAL);
GrantedRemote := (Pending = EPendingMode.PENDING_REMOTE);
GrantedAuto   := (Pending = EPendingMode.PENDING_AUTO);
GrantedRemoteMobile := (Pending = EPendingMode.PENDING_REMOTE_MOBILE);

// Manual input - with an added abstraction layer after the hardware channels
ReqManual := xReqManual; 
AckManual := xAckManual; 
RelManual := xRelManual; 
HB_Manual_Signal := xHB_Manual; 

// Remote input - from BOOL input
ReqRemote := xReqRemote; 
AckRemote := xAckRemote; 
RelRemote := xRelRemote; 
HB_Remote_Signal := xHB_Remote;

// Autonomous input - from BOOL input
ReqAuto	 := xReqAuto;
AckAuto	 := xAckAuto;
RelAuto	 := xRelAuto;
HB_Auto_Signal   := xHB_Auto;

// Remote mobile - from BOOL input
ReqRemoteMobile := xReqRemoteMobile; 
AckRemoteMobile := xAckRemoteMobile; 
RelRemoteMobile := xRelRemoteMobile;
HB_Remote_Mobile_Signal := xHB_Remote_Mobile;

//No outputs are active during INIT or FAILSAFE
IF Active = EControlMode.INIT OR Active = EControlMode.FAILSAFE THEN 
	OUT_ActiveManual := FALSE; 
	OUT_ActiveRemote  := FALSE;
	OUT_ActiveAuto    := FALSE;
	OUT_ActiveRemoteMobile := FALSE; 
	OUT_GrantedManual := FALSE; 
	OUT_GrantedRemote := FALSE; 
	OUT_GrantedAuto	  := FALSE;
	OUT_GrantedRemoteMobile := FALSE; 
	OUT_Pending		  := FALSE; 
	OUT_PendingReady  := FALSE; 
	OUT_Released	  := FALSE; 
ELSE
	OUT_GrantedManual := GrantedManual; 
	OUT_GrantedRemote := GrantedRemote; 
	OUT_GrantedAuto	  := GrantedAuto;
	OUT_GrantedRemoteMobile := GrantedRemoteMobile; 
	OUT_ActiveManual  := (Active = EControlMode.MANUAL); 
	OUT_ActiveRemote  := (Active = EControlMode.REMOTE);
	OUT_ActiveAuto    := (Active = EControlMode.AUTO);
	OUT_ActiveRemoteMobile := (Active = EControlMode.REMOTE_MOBILE); 
	OUT_Pending		  := (State = ETransitionState.VALIDATE_TAKEOVER) OR 
						 (State = ETransitionState.PRE_TAKEOVER); 
	OUT_PendingReady  := PendingReady; 
	OUT_Released	  := Released; 
END_IF
OUT_FailSafe	  := (Active = EControlMode.FAILSAFE);  
OUT_RejectedRequestFlag := GVL_State.RejectedRequestFlag; 
//Heartbeat should be visible regardless of mode we're in
OUT_NoHB_Manual   := NOT HB_Manual_OK; 
OUT_NoHB_Remote   := NOT HB_Remote_OK; 
OUT_NoHB_Auto	  := NOT HB_Auto_OK;
OUT_NoHB_RemoteMobile := NOT HB_Remote_Mobile_OK; 

OUT_State_Stable := (State = ETransitionState.STABLE); 
OUT_State_Validate := (State = ETransitionState.VALIDATE_TAKEOVER); 
OUT_State_FailSafe := (State = ETransitionState.FAILSAFE);

//Start timer
tonToggle(IN := xEnable, PT := T#200MS);

//När timer gått, växla signal
IF tonToggle.Q THEN
	xSignal 		:= NOT xSignal;
	tonToggle(IN 	:= FALSE, PT := GVL_HeartBeat.HB_Generator_Interval);
	xEnable 		:= TRUE;
END_IF;

//Heartbeat-generatorns intervall och heartbeat-monitorns 
//timeout är två separata värden utan formell koppling.
// Om något värde ändras utan att det andra justeras kan
// heartbeat-detektionen sluta fungera.

IF (ReqManual AND ReqRemote) OR //two stations want control
   (ReqManual AND ReqAuto) 	 OR	 
   (ReqManual AND ReqRemoteMobile) OR   
   (ReqRemote AND ReqAuto)	 OR
   (ReqRemote AND ReqRemoteMobile) OR 
   (ReqAuto AND ReqRemoteMobile) THEN

   	Valid        := FALSE; 
    ReqManual_Out := FALSE;
    ReqRemote_Out := FALSE;
	ReqAuto_Out	  := FALSE;
	ReqRemoteMobile_Out := FALSE; 
    AckManual_Out := AckManual;
    AckRemote_Out := AckRemote;
	AckAuto_Out	  := AckAuto;
	AckRemoteMobile_Out := AckRemoteMobile; 
    RelManual_Out := RelManual;
    RelRemote_Out := RelRemote;
	RelAuto_Out	  := RelAuto;
	RelRemoteMobile_Out := RelRemoteMobile; 
    HB_Manual_Out := HB_Manual_Signal;
	HB_Remote_Out := HB_Remote_Signal;
	HB_Auto_Out	  := HB_Auto_Signal;
	HB_Remote_Mobile_Out := HB_Remote_Mobile_Signal; 
    RETURN;
END_IF

IF (ReqManual AND RelManual) OR //a station requesting and releasing at the same time
   (ReqRemote AND RelRemote) OR
   (ReqAuto AND RelAuto) OR
   (ReqRemoteMobile AND RelRemoteMobile) OR 
   (AckManual AND RelManual) OR //Station acknowledging and releasing simutaneously 
   (AckRemote AND RelRemote) OR
   (AckAuto AND RelAuto) OR
   (AckRemoteMobile AND RelRemoteMobile) THEN
   	Valid        := FALSE; 
    ReqManual_Out := FALSE;
    ReqRemote_Out := FALSE;
	ReqAuto_Out	  := FALSE;
	ReqRemoteMobile_Out := FALSE; 
    AckManual_Out := FALSE;
    AckRemote_Out := FALSE;
	AckAuto_Out	  := FALSE;
	AckRemoteMobile_Out := FALSE; 
    RelManual_Out := FALSE;
    RelRemote_Out := FALSE;
	RelAuto_Out	  := FALSE;
	RelRemoteMobile_Out := FALSE; 
    HB_Manual_Out := FALSE;
	HB_Remote_Out := FALSE;
	HB_Auto_Out	  := FALSE;
	HB_Remote_Mobile_Out := FALSE; 
    RETURN;
END_IF

Valid         := TRUE;
ReqManual_Out := ReqManual;
ReqRemote_Out := ReqRemote;
ReqAuto_Out	  := ReqAuto;
ReqRemoteMobile_Out := ReqRemoteMobile;
AckManual_Out := AckManual;
AckRemote_Out := AckRemote;
AckAuto_Out	  := AckAuto;
AckRemoteMobile_Out := AckRemoteMobile; 
RelManual_Out := RelManual;
RelRemote_Out := RelRemote;
RelAuto_Out   := RelAuto;
RelRemoteMobile_Out := RelRemoteMobile; 
HB_Manual_Out := HB_Manual_Signal;
HB_Remote_Out := HB_Remote_Signal;
HB_Auto_Out	  := HB_Auto_Signal;
HB_Remote_Mobile_Out := HB_Remote_Mobile_Signal;

IF Active <> LastActive THEN
		GVL_State.LastActiveBeforeTransition := LastActive;
END_IF
IF Active <> LastActive OR Pending <> LastPending OR State <> LastState THEN 
	SysTimeRtc.SysTimeRtcGet(GVL_State.TimeStamp);
	GVL_State.Active := Active; 
	GVL_State.Pending := Pending; 
	GVL_State.State := State;

	LastActive := Active; 
 	LastPending := Pending; 
	LastState := State; 
END_IF

IF RejectedRequestFlag AND NOT LastRejectedRequest THEN
	GVL_State.RejectedRequestFlag := TRUE; //log the rejection
	GVL_State.RejectionReason := RejectionReason; 
END_IF
LastRejectedRequest := RejectedRequestFlag;
